  "company.support.card1": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M15 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="m16 11 2 2 4-4"></path></svg></div><h3>A real person runs your go-live</h3><p>Not a video guide or a knowledge base. Someone from our team maps your operation, loads your catalog, connects your sensors, and trains your people directly.</p>`,
  "company.support.card2": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 15v-3a8 8 0 0 1 16 0v3"></path><path d="M18 19a2 2 0 0 0 2-2v-2h-4v4z"></path><path d="M6 19a2 2 0 0 1-2-2v-2h4v4z"></path><path d="M10 19h4"></path></svg></div><h3>You talk to people, not tickets</h3><p>When something breaks or needs adjustment, you reach our team directly. No bot, no ticket queue, no waiting days for a useful answer.</p>`,
  "company.support.card3": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect><line x1="16" y1="2" x2="16" y2="6"></line><line x1="8" y1="2" x2="8" y2="6"></line><line x1="3" y1="10" x2="21" y2="10"></line><path d="M8 15h4"></path><path d="M8 18h8"></path></svg></div><h3>We stay 30 days after go-live</h3><p>We monitor your first real dispatches, confirm thermal data syncs correctly, and verify FEFO works in operation before stepping back.</p>`,
  "company.support.card4": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg></div><h3>Your data stays yours</h3><p>Your inventory, routes, customers, and temperature logs belong to your operation. We never sell or share your information. You can export everything at any time.</p>`,
  "company.support.card5": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="4" y="4" width="16" height="16" rx="2" ry="2"></rect><rect x="9" y="9" width="6" height="6"></rect><line x1="9" y1="1" x2="9" y2="4"></line><line x1="15" y1="1" x2="15" y2="4"></line><line x1="9" y1="20" x2="9" y2="23"></line><line x1="15" y1="20" x2="15" y2="23"></line></svg></div><h3>Works with your current equipment</h3><p>We don't force you to buy new hardware. If you already have sensors, we connect to them. If not, we recommend options based on your budget and operation.</p>`,
  "company.support.card6": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M8.5 16.5a5 5 0 0 1 7 0"></path><path d="M5 13a10 10 0 0 1 14 0"></path><path d="M2 9.5a15 15 0 0 1 4.36-3.14"></path><path d="M22 9.5a15 15 0 0 0-4.36-3.14"></path><path d="M12 20h.01"></path><path d="M3 3l18 18"></path></svg></div><h3>Works offline</h3><p>Drivers in low-signal areas? The mobile interface keeps logging temperature, signatures, and GPS. Everything syncs automatically when connectivity returns.</p>`,
  "company.thesis.badge": "Built by operators",
  "company.thesis.title": "We build software because we lived the problem.",
  "company.thesis.body1": "Nexa was born in Lima, Peru, with a team of engineers and supply chain operators. We saw first-hand the operational leakage that appears when cheese, charcuterie, and dairy distribution depends on disconnected logs, generic ERPs, and fragmented WhatsApp.",
  "company.thesis.body2": "We don't sell visionary promises. We deploy hard operational fixes. When you work with us, the team that converts your physical flow into reliable digital infrastructure works with you directly.",
  "company.thesis.cta": "Talk to the deployment team →",
