  "solutions.meta.description": "Nexa Solutions — Built for importers, distributors, and cold storage operators of charcuterie, cheese, and dairy.",
  "solutions.meta.ogTitle": "Nexa Solutions — Built for the nodes that matter most",
  "solutions.meta.ogDescription": "Every refrigerated segment has different demands. Nexa adapts to yours, from cheese and dairy import to last-mile distribution.",
  "solutions.meta.title": "Nexa Solutions — Built for the nodes that matter most",
