  "solutions.route.importers": `<div class="solution-route-meta">Port to warehouse</div><h2 class="solution-route-title">Importers & wholesalers</h2><p class="solution-route-copy">Track container condition before receiving, map cheese and dairy batches on arrival, and separate compromised cargo before it enters saleable inventory.</p><ul class="solution-route-list"><li>Container tracking from origin to warehouse</li><li>Live thermal integrity monitoring</li><li>Bulk inventory mapping</li></ul><a href="solutions-importers.html" class="solution-route-cta">Explore for importers</a>`,
  "solutions.route.distributors": `<div class="solution-route-meta">Warehouse to route</div><h2 class="solution-route-title">Distributors</h2><p class="solution-route-copy">Replace WhatsApp orders with a live flow from B2B intake to FEFO dispatch and signed proof of delivery.</p><ul class="solution-route-list"><li>Self-service B2B portal</li><li>Automated batch-level FEFO</li><li>Digital POD with delivery temperature</li></ul><a href="solutions-distributors.html" class="solution-route-cta">Explore for distributors</a>`,
  "solutions.route.storage": `<div class="solution-route-meta">Facility monitoring</div><h2 class="solution-route-title">Cold storage operators</h2><p class="solution-route-copy">Unify chamber monitoring, escalation, and audit outputs so compliance no longer lives on loose sheets or USB exports.</p><ul class="solution-route-list"><li>Centralized multi-chamber monitoring</li><li>Automatic compliance reports</li><li>Smart alert dispatch</li></ul><a href="solutions-cold-storage.html" class="solution-route-cta">Explore for cold storage</a>`,
  "solutions.advantage.badge": "Shared infrastructure",
  "solutions.advantage.title": "Why operators choose Nexa instead of building their own.",
  "solutions.advantage.copy": "Custom logistics software takes 18 months and costs far more than the problem it's trying to solve. Nexa is production-ready today.",
  "solutions.advantage.card1": `<div class="advantage-icon" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg></div><h3>Operational in days</h3><p>From signed contract to live inventory in under two weeks. Our structured go-live eliminates months of configuration.</p>`,
  "solutions.advantage.card2": `<div class="advantage-icon" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="4" y="4" width="16" height="16" rx="2" ry="2"></rect><rect x="9" y="9" width="6" height="6"></rect><line x1="9" y1="1" x2="9" y2="4"></line><line x1="15" y1="1" x2="15" y2="4"></line><line x1="9" y1="20" x2="9" y2="23"></line><line x1="15" y1="20" x2="15" y2="23"></line><line x1="20" y1="9" x2="23" y2="9"></line><line x1="20" y1="14" x2="23" y2="14"></line><line x1="1" y1="9" x2="4" y2="9"></line><line x1="1" y1="14" x2="4" y2="14"></line></svg></div><h3>Hardware mapped in 48h</h3><p>Already using Onset, Sensitech, or another provider? Nexa connects to your existing IoT infrastructure without forcing you to change anything.</p>`,
  "solutions.advantage.card3": `<div class="advantage-icon" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><ellipse cx="12" cy="5" rx="9" ry="3"></ellipse><path d="M21 12c0 1.66-4.03 3-9 3S3 13.66 3 12"></path><path d="M3 5v14c0 1.66 4.03 3 9 3s9-1.34 9-3V5"></path></svg></div><h3>Zero WhatsApp handoffs</h3><p>From the dock to the final dispatch, the operation lives in one screen. No more chasing confirmations on paper and forwarded emails.</p>`,
  "solutions.compat.label": "Works with your current operation",
  "solutions.compat.copy": "Sensor feeds, ERP layers, and open APIs live under the same operational model. Nexa stabilizes execution without forcing you to replace everything around it.",
